   .collection<RecursivePet>("<your collection>")
   .findOne({ "pet.age": "Spot" });

database
   .collection<RecursivePet>("<your collection>")
   .findOne({ pet: "Spot" });

interface Pet {
   handler?: Handler;
   name: string;
   age: number;
}

interface Handler {
   pet: Pet;
   name: string;
}

database
   .collection<Pet>("<your collection>")
   .findOne({'handler.pet.handler.pet.age': "four"});

